import{_ as t,c as o,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"ToS 警告：帳戶風險與安全實踐 | Antigravity Auth","description":"學習 Antigravity Auth 外掛的使用風險和帳戶安全實踐。了解高風險情境、影子封禁機制和速率限制區別，掌握多帳戶策略、使用量控制和帳戶熱身方法。","frontmatter":{"title":"ToS 警告：帳戶風險與安全實踐 | Antigravity Auth","sidebarTitle":"別讓帳戶被封","subtitle":"ToS 警告：帳戶風險與安全實踐","description":"學習 Antigravity Auth 外掛的使用風險和帳戶安全實踐。了解高風險情境、影子封禁機制和速率限制區別，掌握多帳戶策略、使用量控制和帳戶熱身方法。","tags":["FAQ","風險提示","帳戶安全"],"prerequisite":["start-quick-install"],"order":5},"headers":[],"relativePath":"zh-tw/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md","filePath":"zh-tw/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"}'),r={name:"zh-tw/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"};function e(n,l,s,d,h,g){return a(),o("div",null,[...l[0]||(l[0]=[i('<h1 id="tos-警告" tabindex="-1">ToS 警告 <a class="header-anchor" href="#tos-警告" aria-label="Permalink to &quot;ToS 警告&quot;">​</a></h1><p>學完這課，你能了解使用 Antigravity Auth 外掛可能面臨的風險，以及如何保護你的 Google 帳戶安全。</p><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>你在考慮使用 Antigravity Auth 外掛存取 Google Antigravity 的 AI 模型，但有些擔憂：</p><ul><li>看到社群有人回報帳戶被封禁或影子封禁</li><li>擔心使用非官方工具違反 Google 的服務條款</li><li>不確定是否應該用新帳戶還是舊帳戶</li><li>想知道如何降低風險</li></ul><p>這些擔憂是合理的。使用任何非官方工具都有一定風險，本文將幫你了解具體的風險點和應對策略。</p><h2 id="什麼時候需要看這一課" tabindex="-1">什麼時候需要看這一課 <a class="header-anchor" href="#什麼時候需要看這一課" aria-label="Permalink to &quot;什麼時候需要看這一課&quot;">​</a></h2><ul><li><strong>安裝外掛前</strong>：了解風險後再決定是否使用</li><li><strong>選擇帳戶時</strong>：決定用哪個 Google 帳戶進行認證</li><li><strong>遇到封禁時</strong>：了解可能的原因和預防措施</li><li><strong>新用戶註冊時</strong>：避免高風險操作模式</li></ul><hr><h2 id="核心風險概述" tabindex="-1">核心風險概述 <a class="header-anchor" href="#核心風險概述" aria-label="Permalink to &quot;核心風險概述&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">重要警告</p><p><strong>使用此外掛可能會違反 Google 的服務條款（Terms of Service）。</strong></p><p>少數用戶回報他們的 Google 帳戶被封禁或影子封禁（Shadow Ban，即限制存取但沒有明確通知）。</p><p><strong>使用此外掛即表示你接受以下聲明：</strong></p><ol><li>這是非官方工具，未獲得 Google 認可或背書</li><li>你的 Google 帳戶可能會被暫停或永久封禁</li><li>你自行承擔使用此外掛的所有風險和後果</li></ol></div><h3 id="什麼是影子封禁" tabindex="-1">什麼是影子封禁？ <a class="header-anchor" href="#什麼是影子封禁" aria-label="Permalink to &quot;什麼是影子封禁？&quot;">​</a></h3><p><strong>影子封禁（Shadow Ban）</strong> 是 Google 對可疑帳戶採取的一種限制措施。與直接封禁不同，影子封禁不會顯示明確的錯誤訊息，而是：</p><ul><li>API 請求回傳 403 或 429 錯誤</li><li>配額顯示可用，但實際無法呼叫</li><li>其他帳戶正常運作，只有被標記的帳戶受影響</li></ul><p>影子封禁通常持續時間較長（幾天到幾週），且無法透過申訴恢復。</p><hr><h2 id="高風險情境" tabindex="-1">高風險情境 <a class="header-anchor" href="#高風險情境" aria-label="Permalink to &quot;高風險情境&quot;">​</a></h2><p>以下情境會顯著增加帳戶被標記或封禁的風險：</p><h3 id="🚨-情境-1-全新的-google-帳戶" tabindex="-1">🚨 情境 1：全新的 Google 帳戶 <a class="header-anchor" href="#🚨-情境-1-全新的-google-帳戶" aria-label="Permalink to &quot;🚨 情境 1：全新的 Google 帳戶&quot;">​</a></h3><p><strong>風險等級：極高</strong></p><p>全新註冊的 Google 帳戶使用本外掛，被封禁的機率非常高。原因：</p><ul><li>新帳戶缺少歷史行為資料，容易被 Google 的濫用偵測系統標記</li><li>大量 API 呼叫在新帳戶上會被視為異常行為</li><li>Google 對新帳戶的審核更嚴格</li></ul><p><strong>建議</strong>：不要為此外掛專門建立新帳戶。</p><h3 id="🚨-情境-2-新帳戶-pro-ultra-訂閱" tabindex="-1">🚨 情境 2：新帳戶 + Pro/Ultra 訂閱 <a class="header-anchor" href="#🚨-情境-2-新帳戶-pro-ultra-訂閱" aria-label="Permalink to &quot;🚨 情境 2：新帳戶 + Pro/Ultra 訂閱&quot;">​</a></h3><p><strong>風險等級：極高</strong></p><p>新註冊的帳戶並立即訂閱 Google 的 Pro 或 Ultra 服務，經常被標記並封禁。原因：</p><ul><li>訂閱後的高用量模式在新帳戶上看起來像濫用</li><li>Google 對新付費用戶的審核更嚴格</li><li>這種模式與正常用戶的成長路徑差異太大</li></ul><p><strong>建議</strong>：讓帳戶先「自然成長」一段時間（至少幾個月），再考慮訂閱。</p><h3 id="🟡-情境-3-短時間內大量請求" tabindex="-1">🟡 情境 3：短時間內大量請求 <a class="header-anchor" href="#🟡-情境-3-短時間內大量請求" aria-label="Permalink to &quot;🟡 情境 3：短時間內大量請求&quot;">​</a></h3><p><strong>風險等級：高</strong></p><p>在短時間內發起大量 API 請求，或頻繁使用並行代理/多工作階段，會觸發速率限制和濫用偵測。原因：</p><ul><li>OpenCode 的請求模式比原生應用程式更密集（工具呼叫、重試、串流傳輸等）</li><li>高並行請求會觸發 Google 的保護機制</li></ul><p><strong>建議</strong>：</p><ul><li>控制請求頻率和並行數</li><li>避免同時啟動多個並行代理</li><li>使用多帳戶輪換分散請求</li></ul><h3 id="🟡-情境-4-使用唯一的-google-帳戶" tabindex="-1">🟡 情境 4：使用唯一的 Google 帳戶 <a class="header-anchor" href="#🟡-情境-4-使用唯一的-google-帳戶" aria-label="Permalink to &quot;🟡 情境 4：使用唯一的 Google 帳戶&quot;">​</a></h3><p><strong>風險等級：中</strong></p><p>如果你只有一個 Google 帳戶，且依賴它存取關鍵服務（Gmail、Drive 等），風險較高。原因：</p><ul><li>帳戶被封禁會影響你的日常工作</li><li>無法透過申訴恢復</li><li>備用方案缺失</li></ul><p><strong>建議</strong>：使用一個不依賴關鍵服務的獨立帳戶。</p><hr><h2 id="最佳實踐建議" tabindex="-1">最佳實踐建議 <a class="header-anchor" href="#最佳實踐建議" aria-label="Permalink to &quot;最佳實踐建議&quot;">​</a></h2><h3 id="✅-推薦做法" tabindex="-1">✅ 推薦做法 <a class="header-anchor" href="#✅-推薦做法" aria-label="Permalink to &quot;✅ 推薦做法&quot;">​</a></h3><p><strong>1. 使用已建立的 Google 帳戶</strong></p><p>優先選擇已使用一段時間（建議 6 個月以上）的 Google 帳戶：</p><ul><li>有正常的 Google 服務使用歷史（Gmail、Drive、Google Search 等）</li><li>沒有歷史違規記錄</li><li>帳戶綁定了手機號並完成驗證</li></ul><p><strong>2. 設定多個帳戶</strong></p><p>新增多個 Google 帳戶，透過輪換分散請求：</p><ul><li>至少設定 2-3 個帳戶</li><li>使用 <code>account_selection_strategy: &quot;hybrid&quot;</code> 策略（預設）</li><li>遇到限速時自動切換帳戶</li></ul><p><strong>3. 控制使用量</strong></p><ul><li>避免短時間內密集請求</li><li>減少並行代理的數量</li><li>在 <code>antigravity.json</code> 中設定 <code>max_rate_limit_wait_seconds: 0</code> 快速失敗而不是重試</li></ul><p><strong>4. 監控帳戶狀態</strong></p><p>定期檢查帳戶狀態：</p><ul><li>查看 <code>~/.config/opencode/antigravity-accounts.json</code> 中的 <code>rateLimitResetTimes</code></li><li>啟用除錯日誌：<code>OPENCODE_ANTIGRAVITY_DEBUG=1 opencode</code></li><li>遇到 403/429 錯誤時暫停使用 24-48 小時</li></ul><p><strong>5. 先在官方介面「熱身」</strong></p><p>社群用戶回報的有效方法：</p><ol><li>在瀏覽器中登入 <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a></li><li>執行幾個簡單的提示（如「你好」、「2+2 等於幾」）</li><li>5-10 次成功呼叫後，再使用外掛</li></ol><p><strong>原理</strong>：透過官方介面使用帳戶會讓 Google 認為這是正常用戶行為，降低被標記的風險。</p><h3 id="❌-避免的做法" tabindex="-1">❌ 避免的做法 <a class="header-anchor" href="#❌-避免的做法" aria-label="Permalink to &quot;❌ 避免的做法&quot;">​</a></h3><ul><li>❌ 專門為此外掛建立全新的 Google 帳戶</li><li>❌ 在新註冊的帳戶上立即訂閱 Pro/Ultra</li><li>❌ 用唯一的關鍵服務帳戶（如工作信箱）</li><li>❌ 觸發 429 限制後反覆重試</li><li>❌ 同時啟動大量並行代理</li><li>❌ 提交 <code>antigravity-accounts.json</code> 到版本控制</li></ul><hr><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><h3 id="q-我的帳戶被封禁了-能申訴嗎" tabindex="-1">Q: 我的帳戶被封禁了，能申訴嗎？ <a class="header-anchor" href="#q-我的帳戶被封禁了-能申訴嗎" aria-label="Permalink to &quot;Q: 我的帳戶被封禁了，能申訴嗎？&quot;">​</a></h3><p><strong>A: 不能。</strong></p><p>如果是透過本外掛觸發 Google 的濫用偵測導致的封禁或影子封禁，通常無法透過申訴恢復。原因：</p><ul><li>封禁是基於 API 使用模式自動觸發的</li><li>Google 對非官方工具的使用持嚴格態度</li><li>申訴時需要說明工具用途，但本外掛本身就可能被視為違規</li></ul><p><strong>建議</strong>：</p><ul><li>使用其他未受影響的帳戶</li><li>如果所有帳戶都被封禁，直接使用 <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a></li><li>避免在被封禁的帳戶上繼續嘗試</li></ul><h3 id="q-使用本外掛一定會被封禁嗎" tabindex="-1">Q: 使用本外掛一定會被封禁嗎？ <a class="header-anchor" href="#q-使用本外掛一定會被封禁嗎" aria-label="Permalink to &quot;Q: 使用本外掛一定會被封禁嗎？&quot;">​</a></h3><p><strong>A: 不一定。</strong></p><p>大多數用戶使用本外掛沒有遇到問題。風險取決於：</p><ul><li>帳戶年齡和歷史行為</li><li>使用頻率和請求模式</li><li>是否遵循最佳實踐</li></ul><p><strong>風險評估</strong>：</p><ul><li>舊帳戶 + 適度使用 + 多帳戶輪換 → 低風險</li><li>新帳戶 + 密集請求 + 單帳戶 → 高風險</li></ul><h3 id="q-影子封禁和速率限制有什麼區別" tabindex="-1">Q: 影子封禁和速率限制有什麼區別？ <a class="header-anchor" href="#q-影子封禁和速率限制有什麼區別" aria-label="Permalink to &quot;Q: 影子封禁和速率限制有什麼區別？&quot;">​</a></h3><p><strong>A: 本質不同，恢復方式也不同。</strong></p><table tabindex="0"><thead><tr><th>特徵</th><th>影子封禁</th><th>速率限制（429）</th></tr></thead><tbody><tr><td>觸發原因</td><td>濫用偵測，被標記為可疑</td><td>請求頻率超過配額</td></tr><tr><td>錯誤碼</td><td>403 或靜默失敗</td><td>429 Too Many Requests</td></tr><tr><td>持續時間</td><td>幾天到幾週</td><td>幾小時到一天</td></tr><tr><td>恢復方法</td><td>無法恢復，需用其他帳戶</td><td>等待重設或切換帳戶</td></tr><tr><td>是否可預防</td><td>遵循最佳實踐降低風險</td><td>控制請求頻率</td></tr></tbody></table><h3 id="q-可以用企業-google-帳戶嗎" tabindex="-1">Q: 可以用企業 Google 帳戶嗎？ <a class="header-anchor" href="#q-可以用企業-google-帳戶嗎" aria-label="Permalink to &quot;Q: 可以用企業 Google 帳戶嗎？&quot;">​</a></h3><p><strong>A: 不推薦。</strong></p><p>企業帳戶通常綁定關鍵服務和資料，封禁影響更嚴重。此外：</p><ul><li>企業帳戶的審核更嚴格</li><li>可能違反企業的 IT 政策</li><li>風險由個人承擔，但影響團隊</li></ul><p><strong>建議</strong>：使用個人帳戶。</p><h3 id="q-多帳戶能完全避免封禁嗎" tabindex="-1">Q: 多帳戶能完全避免封禁嗎？ <a class="header-anchor" href="#q-多帳戶能完全避免封禁嗎" aria-label="Permalink to &quot;Q: 多帳戶能完全避免封禁嗎？&quot;">​</a></h3><p><strong>A: 不能完全避免，但能降低影響。</strong></p><p>多帳戶的作用：</p><ul><li>分散請求，降低單個帳戶觸發限制的機率</li><li>一個帳戶被封禁，其他帳戶仍然可用</li><li>遇到限制時自動切換，提高可用性</li></ul><p><strong>但多帳戶不是「護身符」</strong>：</p><ul><li>如果所有帳戶都觸發濫用偵測，可能全部被封禁</li><li>不要濫用多帳戶進行密集請求</li><li>每個帳戶仍需遵循最佳實踐</li></ul><hr><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><p>閱讀完本課，你應該知道：</p><ul><li>[ ] 使用本外掛可能違反 Google ToS，風險自負</li><li>[ ] 新帳戶 + Pro/Ultra 訂閱是高風險情境</li><li>[ ] 推薦使用已建立的 Google 帳戶</li><li>[ ] 設定多個帳戶可以分散風險</li><li>[ ] 帳戶被封禁後無法申訴恢復</li><li>[ ] 控制請求頻率和使用量很重要</li></ul><hr><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>本課介紹了使用 Antigravity Auth 外掛可能面臨的風險：</p><ol><li><strong>核心風險</strong>：可能違反 Google ToS，帳戶可能被封禁或影子封禁</li><li><strong>高風險情境</strong>：新帳戶、新帳戶 + 訂閱、密集請求、單一關鍵帳戶</li><li><strong>最佳實踐</strong>：使用舊帳戶、設定多帳戶、控制使用量、監控狀態、先「熱身」</li><li><strong>常見問題</strong>：無法申訴、風險因人而異、多帳戶可降低影響</li></ol><p>使用本外掛前，請仔細評估風險。如果你無法接受帳戶可能被封禁的後果，建議直接使用 <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a>。</p><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><p>本課內容基於專案 README 文件的風險警告部分（README.md:23-40），不涉及具體程式碼實作。</p><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>ToS 警告聲明</td><td><a href="https://github.com/NoeFabris/opencode-antigravity-auth/blob/main/README.md#L23-L40" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>23-40</td></tr></tbody></table></details>',99)])])}const c=t(r,[["render",e]]);export{u as __pageData,c as default};
